import xml.etree.ElementTree as ET

def xml_to_dict(xml_file):
    settings = {}
    tree = ET.parse(xml_file)
    root = tree.getroot()

    for elem in root:
        key = elem.tag.split('}')[-1]
        value = elem.text
        if value:  # only add key-value pairs where there is text
            settings[key] = value

    return settings